<?php
namespace App\Controllers;use App\Core\Auth;use App\Core\Database;use App\Core\View;
final class NotificationPreferenceController{public function index():void{Auth::requireLogin();$q=Database::connection()->prepare('SELECT * FROM users WHERE id=?');$q->execute([Auth::id()]);View::render('portal/preferences/index',['title'=>'Notification Preferences','user'=>$q->fetch()],'portal');}public function update():void{Auth::requireLogin();verify_csrf();Database::connection()->prepare('UPDATE users SET notification_email=?,notification_sms=?,notification_teams=?,mobile_phone=? WHERE id=?')->execute([isset($_POST['notification_email'])?1:0,isset($_POST['notification_sms'])?1:0,isset($_POST['notification_teams'])?1:0,trim($_POST['mobile_phone']??''),Auth::id()]);flash('success','Notification preferences updated.');redirect('/portal/preferences');}}
